import React from 'react';
import './Multimedia.css';
import Slideshow from './Slideshow.js';

const headline = 'Rats Orchestrate Takeover of New York City';

class Multimedia extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      min: 0,
      max: 27,
      index: 0,
    };
  }

  render() {
    return (
      <div className='Multimedia'>
        <button onClick={this.setState({index: this.state.index+1})}>increase</button>
        <button onClick={this.setState({index: this.state.index-1})}>decrease</button>
        {this.state.index}


      </div>
    );
  }
}

export default Multimedia;
